export const Default: Story = {
  play: async ({ canvas }) => {
    await expect(canvas.getByText(/your instagram growth secret/i)).toBeVisible();
    await expect(canvas.getByPlaceholderText(/enter your email/i)).toBeVisible();
  },
};

